    public class UserContextService : IUserContextService
    {
        private readonly IHttpContextAccessor _httpContextAccessor;

        public UserContextService(IHttpContextAccessor httpContextAccessor)
        {
            _httpContextAccessor = httpContextAccessor;
        }

        public string GetUserId()
        {
            var userId = _httpContextAccessor.HttpContext?.User?.FindFirstValue(ClaimTypes.NameIdentifier);
            if (string.IsNullOrEmpty(userId))
                throw new UnauthorizedAccessException("User identity not established.");
            return userId;
        }

        public string GetTenantId()
        {
            var tenantId = _httpContextAccessor.HttpContext?.User?.FindFirstValue("tenant_id");
            if (string.IsNullOrEmpty(tenantId))
                throw new UnauthorizedAccessException("Tenant identity not established.");
            return tenantId;
        }

        public string GetUserRole()
        {
            return _httpContextAccessor.HttpContext?.User?.FindFirstValue(ClaimTypes.Role) ?? "User";
        }

        public bool IsAdmin()
        {
            return GetUserRole().Equals("Admin", StringComparison.OrdinalIgnoreCase);
        }
    }

