                ["Sent"] = new() { "Paid", "Cancelled" },
                ["Paid"] = new() { },  // Terminal state
                ["Cancelled"] = new() { "Draft" }  // Can revert to draft
            };

            return validTransitions.TryGetValue(currentStatus, out var allowed) && allowed.Contains(newStatus);
        }

